  1→import type { ListItemData, SectionData } from '../types';
  2→import { fuzzyScore } from '../utils/fuzzy_search';
  3→import type { CommandRegistration, ExtensionManifest } from './types';
  4→
  5→const commands = new Map<string, CommandRegistration>();
  6→
  7→const sectionOrder: string[] = [];
  8→
  9→export function registerCommand(cmd: CommandRegistration): void {
 10→  commands.set(cmd.id, cmd);
 11→  if (!sectionOrder.includes(cmd.section)) {
 12→    sectionOrder.push(cmd.section);
 13→  }
 14→}
 15→
 16→export function registerExtension(manifest: ExtensionManifest): void {
 17→  for (const cmd of manifest.commands) {
 18→    const section = cmd.section ?? manifest.name;
 19→    registerCommand({
 20→      id: cmd.name,
 21→      name: cmd.title,
 22→      subtitle: cmd.subtitle,
 23→      icon: cmd.icon,
 24→      keywords: cmd.keywords,
 25→      aliases: cmd.aliases,
 26→      section,
 27→      accessories: cmd.accessories,
 28→      detail: cmd.detail,
 29→      component: cmd.component,
 30→      fullView: cmd.fullView,
 31→      extensionId: manifest.id,
 32→    });
 33→  }
 34→}
 35→
 36→export function getCommand(id: string): CommandRegistration | undefined {
 37→  return commands.get(id);
 38→}
 39→
 40→function toListItem(cmd: CommandRegistration): ListItemData {
 41→  return {
 42→    id: cmd.id,
 43→    title: cmd.name,
 44→    subtitle: cmd.subtitle,
 45→    icon: cmd.icon,
 46→    accessories: cmd.accessories,
 47→    detail: cmd.detail,
 48→  };
 49→}
 50→
 51→export function getSections(): SectionData[] {
 52→  const grouped = new Map<string, ListItemData[]>();
 53→
 54→  for (const section of sectionOrder) {
 55→    grouped.set(section, []);
 56→  }
 57→
 58→  for (const cmd of commands.values()) {
 59→    let items = grouped.get(cmd.section);
 60→    if (!items) {
 61→      items = [];
 62→      grouped.set(cmd.section, items);
 63→    }
 64→    items.push(toListItem(cmd));
 65→  }
 66→
 67→  const sections: SectionData[] = [];
 68→  for (const [title, items] of grouped) {
 69→    if (items.length > 0) {
 70→      sections.push({
 71→        title,
 72→        items,
 73→      });
 74→    }
 75→  }
 76→  return sections;
 77→}
 78→
 79→interface ScoredItem {
 80→  item: ListItemData;
 81→  score: number;
 82→  section: string;
 83→}
 84→
 85→function scoreItem(item: ListItemData, query: string): number {
 86→  const cmd = commands.get(item.id);
 87→  const candidates: string[] = [item.title];
 88→  if (item.subtitle) candidates.push(item.subtitle);
 89→  if (cmd?.keywords) candidates.push(...cmd.keywords);
 90→  if (cmd?.aliases) candidates.push(...cmd.aliases);
 91→
 92→  let best = -Infinity;
 93→  for (const text of candidates) {
 94→    const result = fuzzyScore(query, text);
 95→    if (result && result.score > best) {
 96→      best = result.score;
 97→    }
 98→  }
 99→  return best;
100→}
101→
102→export function searchCommands(query: string): SectionData[] {
103→  if (!query) return getSections();
104→
105→  const sections = getSections();
106→  const scored: ScoredItem[] = [];
107→
108→  for (const section of sections) {
109→    for (const item of section.items) {
110→      const s = scoreItem(item, query);
111→      if (s > -Infinity) {
112→        scored.push({
113→          item,
114→          score: s,
115→          section: section.title,
116→        });
117→      }
118→    }
119→  }
120→
121→  scored.sort((a, b) => b.score - a.score);
122→
123→  const sectionMap = new Map<string, ListItemData[]>();
124→  for (const { item, section } of scored) {
125→    let items = sectionMap.get(section);
126→    if (!items) {
127→      items = [];
128→      sectionMap.set(section, items);
129→    }
130→    items.push(item);
131→  }
132→
133→  const result: SectionData[] = [];
134→  for (const section of sections) {
135→    const items = sectionMap.get(section.title);
136→    if (items && items.length > 0) {
137→      result.push({
138→        title: section.title,
139→        items,
140→      });
141→    }
142→  }
143→  return result;
144→}
